export function handlePartyCommandResult(
  conn: WorldConn,
  r: PacketReader,
): void {
  const result = parsePartyCommandResult(r);
  conn.onGroupEvent?.({
    type: "command_result",
    operation: result.operation,
    target: result.member,
    result: result.result,
  });
}

export function handleGroupInviteReceived(
  conn: WorldConn,
  r: PacketReader,
